    institutionalPersonality: "radically student-centered, competency-based, environmental-justice-committed, wilderness-initiation-bonded, self-directed, non-traditional structure-comfortable, Southwest-rooted",
    cultureKeywords: ["Bobcats", "Doorstep Orientation", "Competency-Based", "Self-Designed Curriculum", "Granite Dells", "Adventure Education", "Environmental Justice", "Prescott Arizona"],
    missionOrientation: "Student-designed education in service of environmental and social justice — Prescott's mission is the liberation of learning from institutional constraint",
